// In Program.cs, register the handler:

var builder = WebApplication.CreateBuilder(args);

// Add Problem Details support
builder.Services.AddProblemDetails();

// Register the global exception handler
builder.Services.AddExceptionHandler<GlobalExceptionHandler>();

var app = builder.Build();

// Add the exception handler middleware (should be early in the pipeline)
app.UseExceptionHandler();

// Example endpoints to demonstrate behavior:
app.MapGet("/items/{id}", (int id) =>
{
    if (id < 0) throw new ArgumentException("ID must be positive.");
    if (id == 0) throw new KeyNotFoundException("Item not found.");
    if (id == 999) throw new InvalidOperationException("Item is archived.");
    return Results.Ok(new { Id = id, Name = "Sample" });
});

app.Run();

